#include<bits/stdc++.h>
using namespace std;
struct node{
	int q,w;
}a[505];
int n,ans,f[505];
bool cmp(node a,node b){
	return a.w>b.w;
}
int main(){
    ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++)cin>>a[i].q;
	for(int i=1;i<=n;i++)cin>>a[i].w;
	sort(a+1,a+n+1,cmp);
	for(int i=1;i<=n;i++)
		for(int j=a[i].q;j>0;j--)
			if(!f[j]){
				f[j]=1;
				ans+=a[i].w;
				break;
			}
	cout<<ans;
	return 0;
}
